def validTree(n, edges):
    if len(edges) != n - 1: return False
    adj = [[] for _ in range(n)]
    for u, v in edges: adj[u].append(v); adj[v].append(u)
    visited = {0}; q = [0]
    for u in q:
        for v in adj[u]:
            if v not in visited: visited.add(v); q.append(v)
    return len(visited) == n

